const scenario = JSON.parse(readFileSync(0, "utf8"));
const remainingCapByPolicy = new Map<number, number>();
const results = scenario.steps.map(
  (step: { type: string; policy?: { items: unknown[] } | number; incident?: { cause: string; damages: unknown[] } }) => {
    if (step.type === "quote") {
      const { premium } = quote({
        customer: scenario.customer,
        items: (step.policy as { items: unknown[] }).items as never,
      });
      return { premium };
    }
    if (step.type === "claim") {
      const policyIndex = step.policy as number;
      const referenced = scenario.steps[policyIndex] as { policy: { items: unknown[] } };
      const items = referenced.policy.items;
      const tracked = remainingCapByPolicy.get(policyIndex);
      const claimInput: { items: unknown[]; remainingCap?: number } = { items };
      if (tracked !== undefined) claimInput.remainingCap = tracked;
      const { payout, remainingCap } = claim(
        claimInput as never,
        step.incident as never,
      );
      remainingCapByPolicy.set(policyIndex, remainingCap);
      return { payout, remainingCap };
    }
    return {};
  },
);
